#include <bits/stdc++.h>
using namespace std;
#define int long long
const int mod=100003;
int ans;
int ksm(int n,int m){
	int s=1;
	while(m){
		if(m&1){
			s=s*n%mod;
		}
		n=n*n%mod;
		m>>=1;
	}
	return s;
}
int n,m;
signed main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>m>>n;
	ans=(ksm(m,n)-(m%mod)*ksm(m-1,n-1)%mod);
	while(ans<0){
		ans+=mod;
	}
	ans%=mod;
	cout<<ans;
	return 0;
}
